import{_ as a,o as e,c as n,ag as l}from"./chunks/framework.DXGyWiRo.js";const D=JSON.parse('{"title":"FlashQL Language Reference","description":"","frontmatter":{},"headers":[],"relativePath":"flashql/lang.md","filePath":"flashql/lang.md"}'),o={name:"flashql/lang.md"};function p(t,s,i,c,r,d){return e(),n("div",null,[...s[0]||(s[0]=[l(`<h1 id="flashql-language-reference" tabindex="-1">FlashQL Language Reference <a class="header-anchor" href="#flashql-language-reference" aria-label="Permalink to &quot;FlashQL Language Reference&quot;">​</a></h1><p>This page documents FlashQL&#39;s current SQL surface as it exists in the codebase today.</p><p>It is intentionally written as a usage reference. Also, where support is partial or runtime-specific, that is stated plainly.</p><hr><h2 id="query-language-at-a-glance" tabindex="-1">Query Language at a Glance <a class="header-anchor" href="#query-language-at-a-glance" aria-label="Permalink to &quot;Query Language at a Glance&quot;">​</a></h2><p>FlashQL is strongest today in the application-facing query layer:</p><ul><li><code>SELECT</code></li><li><code>INSERT</code></li><li><code>UPDATE</code></li><li><code>DELETE</code></li><li><code>RETURNING</code></li><li><code>WITH</code> / CTEs</li><li>joins, including <code>LATERAL</code></li><li><code>VALUES</code></li><li>set-returning functions and <code>ROWS FROM</code></li><li>set operations such as <code>UNION</code>, <code>INTERSECT</code>, and <code>EXCEPT</code></li><li>window-function expressions used in tested execution paths</li></ul><p>These are not just parser-level claims. They are exercised across the parser, desugaring layer, and engine tests.</p><hr><h2 id="dql-querying-data" tabindex="-1">DQL: Querying Data <a class="header-anchor" href="#dql-querying-data" aria-label="Permalink to &quot;DQL: Querying Data&quot;">​</a></h2><h3 id="basic-select" tabindex="-1">Basic <code>SELECT</code> <a class="header-anchor" href="#basic-select" aria-label="Permalink to &quot;Basic \`SELECT\`&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT id, name</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM public.users</span></span>
<span class="line"><span style="color:#C3E88D;">  WHERE active = true</span></span>
<span class="line"><span style="color:#C3E88D;">  ORDER BY id</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>Supported common building blocks include:</p><ul><li>projection and aliases</li><li><code>WHERE</code></li><li><code>ORDER BY</code></li><li><code>LIMIT</code> / <code>OFFSET</code></li><li>grouping and aggregates</li><li>subqueries</li></ul><h3 id="joins" tabindex="-1">Joins <a class="header-anchor" href="#joins" aria-label="Permalink to &quot;Joins&quot;">​</a></h3><p>FlashQL supports the mainstream join family:</p><ul><li><code>INNER JOIN</code></li><li><code>LEFT JOIN</code></li><li><code>RIGHT JOIN</code></li><li><code>CROSS JOIN</code></li></ul><p>And it also supports <code>LATERAL</code> joins in tested paths.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT t.id, s.val</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM public.t_nums t</span></span>
<span class="line"><span style="color:#C3E88D;">  CROSS JOIN LATERAL generate_series(1, t.n) AS s(val)</span></span>
<span class="line"><span style="color:#C3E88D;">  ORDER BY t.id, s.val</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT t.id, s.val</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM public.t_nums t</span></span>
<span class="line"><span style="color:#C3E88D;">  LEFT JOIN LATERAL generate_series(1, t.n) AS s(val) ON true</span></span>
<span class="line"><span style="color:#C3E88D;">  ORDER BY t.id, s.val</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><h3 id="values-and-derived-row-sets" tabindex="-1"><code>VALUES</code> and Derived Row Sets <a class="header-anchor" href="#values-and-derived-row-sets" aria-label="Permalink to &quot;\`VALUES\` and Derived Row Sets&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT *</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM (VALUES (1, &#39;Ada&#39;), (2, &#39;Linus&#39;)) AS v(id, name)</span></span>
<span class="line"><span style="color:#C3E88D;">  ORDER BY id</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This is useful when:</p><ul><li>you need a tiny inline dataset</li><li>you want to join query data against app-supplied rows</li><li>you are composing more advanced CTE pipelines</li></ul><h3 id="set-returning-functions-and-rows-from" tabindex="-1">Set-Returning Functions and <code>ROWS FROM</code> <a class="header-anchor" href="#set-returning-functions-and-rows-from" aria-label="Permalink to &quot;Set-Returning Functions and \`ROWS FROM\`&quot;">​</a></h3><p>FlashQL parses and executes tested forms such as:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT *</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM ROWS FROM (</span></span>
<span class="line"><span style="color:#C3E88D;">    generate_series(1, 2),</span></span>
<span class="line"><span style="color:#C3E88D;">    unnest(ARRAY[&#39;a&#39;,&#39;b&#39;])</span></span>
<span class="line"><span style="color:#C3E88D;">  ) AS t(c1, c2)</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This matters because FlashQL is not restricted to base tables. It can treat function output as relational input.</p><h3 id="set-operations" tabindex="-1">Set Operations <a class="header-anchor" href="#set-operations" aria-label="Permalink to &quot;Set Operations&quot;">​</a></h3><p>Supported and tested:</p><ul><li><code>UNION</code></li><li><code>UNION ALL</code></li><li><code>INTERSECT</code></li><li><code>EXCEPT</code></li></ul><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT id FROM public.a</span></span>
<span class="line"><span style="color:#C3E88D;">  UNION ALL</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT id FROM public.b</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><h3 id="ctes" tabindex="-1">CTEs <a class="header-anchor" href="#ctes" aria-label="Permalink to &quot;CTEs&quot;">​</a></h3><p>Common table expressions are an important part of FlashQL&#39;s usable language surface.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  WITH active_users AS (</span></span>
<span class="line"><span style="color:#C3E88D;">    SELECT id, name</span></span>
<span class="line"><span style="color:#C3E88D;">    FROM public.users</span></span>
<span class="line"><span style="color:#C3E88D;">    WHERE active = true</span></span>
<span class="line"><span style="color:#C3E88D;">  )</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT *</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM active_users</span></span>
<span class="line"><span style="color:#C3E88D;">  ORDER BY id</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>Writable CTE pipelines are also part of the tested surface when combined with <code>RETURNING</code>.</p><hr><h2 id="dml-writing-data" tabindex="-1">DML: Writing Data <a class="header-anchor" href="#dml-writing-data" aria-label="Permalink to &quot;DML: Writing Data&quot;">​</a></h2><h3 id="insert" tabindex="-1"><code>INSERT</code> <a class="header-anchor" href="#insert" aria-label="Permalink to &quot;\`INSERT\`&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  INSERT INTO public.users (id, name)</span></span>
<span class="line"><span style="color:#C3E88D;">  VALUES (1, &#39;Ada&#39;), (2, &#39;Linus&#39;)</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>Common tested forms include:</p><ul><li>single-row insert</li><li>multi-row insert</li><li><code>INSERT ... SELECT</code></li><li><code>INSERT ... DEFAULT VALUES</code></li><li><code>INSERT ... RETURNING</code></li></ul><h3 id="update" tabindex="-1"><code>UPDATE</code> <a class="header-anchor" href="#update" aria-label="Permalink to &quot;\`UPDATE\`&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  UPDATE public.users</span></span>
<span class="line"><span style="color:#C3E88D;">  SET name = &#39;Ada Lovelace&#39;</span></span>
<span class="line"><span style="color:#C3E88D;">  WHERE id = 1</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>Tested forms include:</p><ul><li>regular <code>SET</code> expressions</li><li><code>UPDATE ... FROM</code></li><li><code>UPDATE ... RETURNING</code></li></ul><h3 id="delete" tabindex="-1"><code>DELETE</code> <a class="header-anchor" href="#delete" aria-label="Permalink to &quot;\`DELETE\`&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  DELETE FROM public.users</span></span>
<span class="line"><span style="color:#C3E88D;">  WHERE id = 1</span></span>
<span class="line"><span style="color:#C3E88D;">  RETURNING *</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>Tested forms include:</p><ul><li>regular conditional deletes</li><li><code>DELETE ... USING</code></li><li><code>DELETE ... RETURNING</code></li></ul><h3 id="returning" tabindex="-1"><code>RETURNING</code> <a class="header-anchor" href="#returning" aria-label="Permalink to &quot;\`RETURNING\`&quot;">​</a></h3><p><code>RETURNING</code> is a major part of the FlashQL ergonomics story.</p><p>It supports:</p><ul><li><code>RETURNING *</code></li><li>named columns</li><li>aliases</li><li>expressions</li><li>function calls</li><li>subqueries</li><li>DeepRefs</li></ul><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  INSERT INTO public.returning_demo (id, val)</span></span>
<span class="line"><span style="color:#C3E88D;">  VALUES (1, &#39;x&#39;)</span></span>
<span class="line"><span style="color:#C3E88D;">  RETURNING id * 10 AS id_times_10, upper(val) AS upper_val</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><h3 id="upsert" tabindex="-1">UPSERT <a class="header-anchor" href="#upsert" aria-label="Permalink to &quot;UPSERT&quot;">​</a></h3><p>FlashQL supports <code>INSERT ... ON CONFLICT</code> operations.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  INSERT INTO public.users (id, name, age)</span></span>
<span class="line"><span style="color:#C3E88D;">  VALUES (30, &#39;SamX&#39;, 41)</span></span>
<span class="line"><span style="color:#C3E88D;">  ON CONFLICT (id) DO UPDATE</span></span>
<span class="line"><span style="color:#C3E88D;">  SET name = EXCLUDED.name, age = EXCLUDED.age</span></span>
<span class="line"><span style="color:#C3E88D;">  RETURNING *</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>See also: <a href="/lang/upsert">UPSERT</a></p><hr><h2 id="window-functions" tabindex="-1">Window Functions <a class="header-anchor" href="#window-functions" aria-label="Permalink to &quot;Window Functions&quot;">​</a></h2><p>Window functions are part of the parser surface and are exercised in engine tests for tested shapes such as:</p><ul><li><code>ROW_NUMBER() OVER (...)</code></li><li><code>SUM(amount) OVER ()</code></li><li><code>RANK() OVER (...)</code></li></ul><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  WITH changed AS (</span></span>
<span class="line"><span style="color:#C3E88D;">    UPDATE public.returning_demo</span></span>
<span class="line"><span style="color:#C3E88D;">    SET val = &#39;y&#39;</span></span>
<span class="line"><span style="color:#C3E88D;">    WHERE id = 1</span></span>
<span class="line"><span style="color:#C3E88D;">    RETURNING id, val</span></span>
<span class="line"><span style="color:#C3E88D;">  )</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT</span></span>
<span class="line"><span style="color:#C3E88D;">    id,</span></span>
<span class="line"><span style="color:#C3E88D;">    val,</span></span>
<span class="line"><span style="color:#C3E88D;">    ROW_NUMBER() OVER (ORDER BY id) AS rn</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM changed</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This is one of the areas where the older docs were badly behind the code. Window-function support is not merely &quot;planned.&quot;</p><hr><h2 id="ddl-and-schema-operations" tabindex="-1">DDL and Schema Operations <a class="header-anchor" href="#ddl-and-schema-operations" aria-label="Permalink to &quot;DDL and Schema Operations&quot;">​</a></h2><p>FlashQL now exposes a meaningful SQL DDL surface alongside the lower-level storage transaction APIs.</p><h3 id="supported-today" tabindex="-1">Supported Today <a class="header-anchor" href="#supported-today" aria-label="Permalink to &quot;Supported Today&quot;">​</a></h3><p>At the SQL-facing level, tested and used support includes:</p><ul><li><code>CREATE SCHEMA ... WITH (...)</code></li><li><code>ALTER SCHEMA</code></li><li><code>CREATE TABLE</code></li><li><code>ALTER TABLE</code></li><li><code>DROP TABLE</code></li><li><code>CREATE VIEW</code></li><li><code>CREATE MATERIALIZED VIEW</code></li><li><code>CREATE REALTIME VIEW</code></li><li><code>ALTER VIEW</code></li><li><code>DROP VIEW</code></li><li><code>REFRESH VIEW</code></li><li><code>CREATE INDEX</code></li><li><code>ALTER INDEX</code></li><li><code>DROP INDEX</code></li></ul><p>At the storage-transaction level, support exists for:</p><ul><li><code>createTable()</code></li><li><code>alterTable()</code></li><li><code>dropTable()</code></li><li><code>createView()</code></li><li><code>alterView()</code></li><li><code>dropView()</code></li><li><code>createNamespace()</code></li><li><code>alterNamespace()</code></li><li><code>createIndex()</code></li><li><code>alterIndex()</code></li><li><code>dropIndex()</code></li></ul><h3 id="important-nuance-about-dialects" tabindex="-1">Important Nuance About Dialects <a class="header-anchor" href="#important-nuance-about-dialects" aria-label="Permalink to &quot;Important Nuance About Dialects&quot;">​</a></h3><p>The SQL surface is intentionally selective rather than claiming full PostgreSQL or MySQL DDL parity. The parser is dialect-aware and covers the supported overlap plus FlashQL-specific extensions.</p><p>If your application depends on rarely used server-specific DDL clauses, validate those paths explicitly.</p><hr><h2 id="json-literals-and-structured-data" tabindex="-1">JSON Literals and Structured Data <a class="header-anchor" href="#json-literals-and-structured-data" aria-label="Permalink to &quot;JSON Literals and Structured Data&quot;">​</a></h2><p>FlashQL extends SQL with native JSON-style literals.</p><p>See:</p><ul><li><a href="/lang/json-literals">JSON Literals</a></li></ul><p>This matters especially when you want application-shaped SQL without constantly escaping back into imperative JavaScript.</p><hr><h2 id="deeprefs" tabindex="-1">DeepRefs <a class="header-anchor" href="#deeprefs" aria-label="Permalink to &quot;DeepRefs&quot;">​</a></h2><p>DeepRefs are a LinkedQL language extension for relational traversal and structured writes.</p><p>Operators include:</p><ul><li><code>~&gt;</code> for forward traversal</li><li><code>&lt;~</code> for reverse traversal</li></ul><p>Example:</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#F78C6C;">SELECT</span><span style="color:#BABED8;"> title, author ~</span><span style="color:#89DDFF;">&gt;</span><span style="color:#F78C6C;"> name</span></span>
<span class="line"><span style="color:#F78C6C;">FROM</span><span style="color:#BABED8;"> public.posts</span></span></code></pre></div><p>DeepRefs also show up in write syntax and desugaring workflows.</p><p>See: <a href="/lang/deeprefs">DeepRefs</a></p><hr><h2 id="version-binding" tabindex="-1">Version Binding <a class="header-anchor" href="#version-binding" aria-label="Permalink to &quot;Version Binding&quot;">​</a></h2><p>FlashQL supports version-qualified relation references such as:</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#F78C6C;">SELECT</span><span style="color:#89DDFF;"> *</span></span>
<span class="line"><span style="color:#F78C6C;">FROM</span><span style="color:#BABED8;"> public.users@</span><span style="color:#89DDFF;">=</span><span style="color:#F78C6C;">3</span></span></code></pre></div><p>And in joins:</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#F78C6C;">SELECT</span><span style="color:#BABED8;"> a.id, b.name</span></span>
<span class="line"><span style="color:#F78C6C;">FROM</span><span style="color:#BABED8;"> public.vja@</span><span style="color:#89DDFF;">=</span><span style="color:#F78C6C;">1</span><span style="color:#BABED8;"> a</span></span>
<span class="line"><span style="color:#F78C6C;">LEFT JOIN</span><span style="color:#BABED8;"> public.vjb@</span><span style="color:#89DDFF;">=</span><span style="color:#F78C6C;">1</span><span style="color:#BABED8;"> b </span><span style="color:#F78C6C;">ON</span><span style="color:#BABED8;"> a.rel </span><span style="color:#89DDFF;">=</span><span style="color:#BABED8;"> b.id</span></span></code></pre></div><p>What version binding means here:</p><ul><li>the query states the relation version it expects</li><li>if the stored relation version does not satisfy that expectation, the query fails</li></ul><p>What it does <strong>not</strong> mean:</p><ul><li>it is not the same thing as historical row snapshotting</li></ul><p>For point-in-time replay, use FlashQL boot options such as <code>versionStop</code>.</p><p>See: <a href="/lang/version-binding">Version Binding</a></p><hr><h2 id="point-in-time-replay" tabindex="-1">Point-in-Time Replay <a class="header-anchor" href="#point-in-time-replay" aria-label="Permalink to &quot;Point-in-Time Replay&quot;">​</a></h2><p>Point-in-time replay is not a query operator. It is a FlashQL boot mode.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> historical </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#BABED8;">  keyval</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  versionStop</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">public.snap_tbl@1</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> historical</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This replays persisted history to a chosen relation-version boundary and boots the engine there.</p><p>That is separate from version binding inside a query.</p><hr><h2 id="additional-reading" tabindex="-1">Additional Reading <a class="header-anchor" href="#additional-reading" aria-label="Permalink to &quot;Additional Reading&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">If you want to learn about...</th><th style="text-align:left;">Go to...</th></tr></thead><tbody><tr><td style="text-align:left;">the broader LinkedQL language surface</td><td style="text-align:left;"><a href="/lang">Language Surface</a></td></tr><tr><td style="text-align:left;">the common API contract</td><td style="text-align:left;"><a href="/api">Core API</a></td></tr></tbody></table>`,112)])])}const u=a(o,[["render",p]]);export{D as __pageData,u as default};
